(function () {
  const utils = window.IKSASS || {};
  const fetchJson = utils.fetchJson || (async (path) => {
    const res = await fetch(path, { cache: 'no-store' });
    if (!res.ok) throw new Error(path);
    return res.json();
  });

  const BASE_INDEX = [
    { title: 'Berita', url: 'berita/', excerpt: 'Kumpulan kabar dan update terbaru dari IKSASS.', category: 'Navigasi' },
    { title: 'Tentang', url: 'tentang/', excerpt: 'Profil organisasi, sejarah singkat, identitas, dan arah gerak perjuangan IKSASS.', category: 'Navigasi' },
    { title: 'Kelembagaan', url: 'kelembagaan/', excerpt: 'Struktur pengurus, komisariat, rayon, sub-rayon, dan data kelembagaan.', category: 'Navigasi' },
    { title: 'Agenda', url: 'agenda/', excerpt: 'Agenda kegiatan dan jadwal organisasi.', category: 'Navigasi' },
    { title: 'Dokumen', url: 'dokumen/', excerpt: 'Dokumen, arsip, dan publikasi terkait IKSASS.', category: 'Navigasi' },
    { title: 'Galeri', url: 'galeri/', excerpt: 'Galeri foto dan dokumentasi kegiatan.', category: 'Navigasi' },
    { title: 'Info', url: 'info/', excerpt: 'Informasi umum dan pengumuman.', category: 'Navigasi' },
    { title: 'Kontak', url: 'kontak/', excerpt: 'Kontak dan kanal komunikasi resmi.', category: 'Navigasi' },
  ];

  window.SEARCH_INDEX = BASE_INDEX.slice();

  function normalizeTag(value) {
    return String(value || '')
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9\s-]/g, '')
      .replace(/\s+/g, '-')
      .replace(/-+/g, '-');
  }

  function buildTagsFromNewsItem(item) {
    const tags = new Set();
    String(item.slug || '').split('-').filter(Boolean).forEach((token) => tags.add(normalizeTag(token)));
    String(item.location || '').split(/\s+|,|\//).filter(Boolean).forEach((token) => tags.add(normalizeTag(token)));
    if (/^\d{4}-\d{2}-\d{2}$/.test(String(item.date_iso || ''))) tags.add(String(item.date_iso).slice(0, 4));
    return Array.from(tags).filter(Boolean);
  }

  async function buildIndex() {
    const [pagesRaw, newsRaw] = await Promise.all([
      fetchJson('assets/data/pages-index.json'),
      fetchJson('berita/news-index.json'),
    ]);

    const pagesItems = Array.isArray(pagesRaw)
      ? pagesRaw.map((item) => ({
          title: item.title || '',
          url: item.url || '',
          excerpt: item.excerpt || '',
          category: item.category || 'Halaman',
          tags: item.tags || [],
        }))
      : [];

    const beritaItems = (Array.isArray(newsRaw) ? newsRaw : []).map((item) => ({
      title: item.title || '',
      url: `berita/${item.slug}/`,
      excerpt: item.excerpt || '',
      category: 'Berita',
      date: item.date_display || '',
      tags: buildTagsFromNewsItem(item),
    }));

    window.SEARCH_INDEX = BASE_INDEX.concat(pagesItems, beritaItems);
    window.dispatchEvent(new CustomEvent('search:index:ready'));
  }

  buildIndex().catch(() => {
    window.dispatchEvent(new CustomEvent('search:index:ready'));
  });
})();
